let CostData = AICostData_CL | where ChargePeriodStart >= {TimeRange:start} and ChargePeriodStart <= {TimeRange:end} | summarize arg_max(TimeGenerated, *) by ChargePeriodStart, Model, Direction, FoundryResource, Project;
let totalCost = toscalar(CostData | summarize round(sum(BilledCost), 4));
let totalTokens = toscalar(CostData | summarize round(sum(ConsumedQuantity), 0));
let modelCount = toscalar(CostData | summarize dcount(Model));
let daySpan = toscalar(CostData | summarize max_of(datetime_diff('day', max(ChargePeriodStart), min(ChargePeriodStart)) + 1, 1));
let reqCount = toscalar(AzureDiagnostics
| where ResourceProvider == 'MICROSOFT.COGNITIVESERVICES' and Category == 'RequestResponse'
| where OperationName in ('Completions_Create','create_completions','create_response')
| summarize count());
let avgTokensPerReq = iff(reqCount > 0, round((totalTokens * 1.0) / (reqCount * 1.0), 0), 0.0);
let dailyCost = iff(daySpan > 0, round((totalCost * 1.0) / (daySpan * 1.0), 4), 0.0);
let projectedMonthlyCost = round(dailyCost * 30, 2);
let totalTokensK = round((totalTokens * 1.0) / 1000, 1);
CostData
| summarize TotalCost = round(sum(BilledCost), 4), Models = dcount(Model)
| extend DailyCost = dailyCost, Projected = projectedMonthlyCost, TokensK = totalTokensK, Requests = reqCount, AvgTok = avgTokensPerReq
| project
    ['Total Billed Cost ($)'] = TotalCost,
    ['Daily Avg Cost ($)'] = DailyCost,
    ['Projected Monthly ($)'] = Projected,
    ['Total Tokens (K)'] = TokensK,
    ['Requests'] = Requests,
    ['Avg Tokens/Req'] = AvgTok,
    ['Models'] = Models

let CostData = AICostData_CL | where ChargePeriodStart >= {TimeRange:start} and ChargePeriodStart <= {TimeRange:end} | summarize arg_max(TimeGenerated, *) by ChargePeriodStart, Model, Direction, FoundryResource, Project;
let totalTokens = toscalar(CostData | summarize sum(ConsumedQuantity));
let inputTokens = toscalar(CostData | where Direction == 'Input' | summarize sum(ConsumedQuantity));
let outputTokens = toscalar(CostData | where Direction == 'Output' | summarize sum(ConsumedQuantity));
let inputRatio = iff(totalTokens > 0, round(inputTokens / totalTokens, 2), 0.0);
let totalCost = toscalar(CostData | summarize sum(BilledCost));
let reqData = AzureDiagnostics
| where ResourceProvider == 'MICROSOFT.COGNITIVESERVICES' and Category == 'RequestResponse'
| where OperationName in ('Completions_Create','create_completions','create_response');
let totalReqs = toscalar(reqData | summarize count());
let avgLatency = toscalar(reqData | summarize round(avg(todecimal(DurationMs)), 0));
let p95Latency = toscalar(reqData | summarize round(percentile(todecimal(DurationMs), 95), 0));
let maxLatency = toscalar(reqData | summarize round(max(todecimal(DurationMs)), 0));
let avgTokensPerReq = iff(totalReqs > 0, round(totalTokens / (totalReqs * 1.0), 0), 0.0);
let costPerReq = iff(totalReqs > 0, round(totalCost / (totalReqs * 1.0), 6), 0.0);
reqData
| summarize Total = count(), AvgLat = round(avg(todecimal(DurationMs)), 0), P95Lat = round(percentile(todecimal(DurationMs), 95), 0), MaxLat = round(max(todecimal(DurationMs)), 0)
| extend AvgTokPerReq = avgTokensPerReq, CostPer = costPerReq, InRatio = inputRatio
| project
    ['Total Interactions'] = Total,
    ['Avg Tokens/Interaction'] = AvgTokPerReq,
    ['Input/Output Ratio'] = InRatio,
    ['Avg Cost/Interaction ($)'] = CostPer,
    ['Avg Latency (ms)'] = AvgLat,
    ['P95 Latency (ms)'] = P95Lat,
    ['Max Latency (ms)'] = MaxLat

let CostData = AICostData_CL | where ChargePeriodStart >= {TimeRange:start} and ChargePeriodStart <= {TimeRange:end} | summarize arg_max(TimeGenerated, *) by ChargePeriodStart, Model, Direction, FoundryResource, Project;
