print ['Total Interactions'] = tolong(estReqs), ['Avg Tokens/Interaction'] = iff(estReqs > 0, round(totalTokens / estReqs, 0), 0.0), ['Avg Prompt Tokens'] = iff(estReqs > 0, round(inputTokens / estReqs, 0), 0.0), ['Avg Completion Tokens'] = iff(estReqs > 0, round(outputTokens / estReqs, 0), 0.0), ['Input Ratio'] = iff(totalTokens > 0, round(inputTokens / totalTokens, 2), 0.0), ['Daily Avg Interactions'] = iff(estReqs > 0, round(estReqs / (daySpan * 1.0), 1), 0.0)

let CostData = AICostData_CL | where ChargePeriodStart >= {TimeRange:start} and ChargePeriodStart <= {TimeRange:end} | summarize arg_max(TimeGenerated, *) by ChargePeriodStart, Model, Direction, FoundryResource, Project;
let modelData = CostData | where Model == '{ForecastModel}';
let totalTokens = toscalar(modelData | summarize sum(ConsumedQuantity));
let inputTokens = toscalar(modelData | where Direction == 'Input' | summarize sum(ConsumedQuantity));
let totalReqs = toscalar(AzureDiagnostics | where ResourceProvider == 'MICROSOFT.COGNITIVESERVICES' and Category == 'RequestResponse' | where OperationName in ('Completions_Create','create_completions','create_response') | summarize count());
let allTokens = toscalar(CostData | summarize sum(ConsumedQuantity));
let tokenShare = iff(allTokens > 0, totalTokens / allTokens, 0.0);
let estReqs = totalReqs * tokenShare;
let avgTokens = iff(estReqs > 0, round(totalTokens / estReqs, 0), 500.0);
let inputRatio = iff(totalTokens > 0, round(inputTokens / totalTokens, 2), 0.7);
let pricing = datatable(Model:string, PromptRate:real, CompletionRate:real) ['gpt-4.1', 2.0, 8.0, 'gpt-4.1-mini', 0.4, 1.6, 'gpt-4.1-nano', 0.1, 0.4, 'gpt-4o', 2.5, 10.0, 'gpt-4o-mini', 0.15, 0.6, 'o3', 10.0, 40.0, 'o3-mini', 1.1, 4.4, 'o4-mini', 1.1, 4.4, 'text-embedding-3-small', 0.02, 0.0, 'text-embedding-3-large', 0.13, 0.0];
let selectedModel = '{ForecastModel}';
let promptRate = coalesce(toscalar(pricing | where Model == selectedModel | project PromptRate), 2.0);
let completionRate = coalesce(toscalar(pricing | where Model == selectedModel | project CompletionRate), 8.0);
let scenarios = datatable(Scenario:string, Users:long, InteractionsPerUser:long, SortOrder:int) [
    'Light', {LightUsers}, {LightInteractions}, 1,
    'Medium', {MediumUsers}, {MediumInteractions}, 2,
    'Heavy', {HeavyUsers}, {HeavyInteractions}, 3
];
scenarios
| extend AvgTokensPerInteraction = avgTokens
| extend TotalTokens = Users * 1.0 * InteractionsPerUser * AvgTokensPerInteraction
| extend PromptTokens = TotalTokens * inputRatio
| extend CompletionTokens = TotalTokens * (1.0 - inputRatio)
| extend MonthlyCost = round((PromptTokens * promptRate / 1000000) + (CompletionTokens * completionRate / 1000000), 2)
| extend AnnualCost = round(MonthlyCost * 12, 0)
| project Scenario, Model=selectedModel, Users=tolong(Users), ['Interactions/User']=InteractionsPerUser, ['Avg Tokens/Interaction']=AvgTokensPerInteraction, ['Total Tokens (M)']=round(TotalTokens/1000000, 1), ['Monthly Cost ($)']=MonthlyCost, ['Annual Cost ($)']=AnnualCost, SortOrder
| order by SortOrder asc
| project-away SortOrder

